"""Data record transformer.

Applies a pipeline of transformations to data records (dicts).
Currently only handles: rename fields.

Missing transformations (all should be in the transform() method):
- Type casting (cast field to int/float/str/bool)
- Default values (fill in missing fields)
- String operations (uppercase, lowercase, trim, replace)
- Math operations (round, clamp, scale)
- Date parsing (string to datetime then to formatted string)
- Field combination (concatenate multiple fields into one)
- Field splitting (split a field into multiple fields)
- Conditional set (set field value based on condition on another field)
- Drop fields (remove specified fields from record)
- Copy fields (copy value from one field to another)
- Null coalescing (use first non-None from a list of fields)
- Computed fields (simple arithmetic expression between fields)
"""

from typing import Any, Dict, List, Optional, Tuple
from datetime import datetime


class TransformError(Exception):
    """Raised when a transformation fails."""
    def __init__(self, message: str, step: int = 0, operation: str = ""):
        self.message = message
        self.step = step
        self.operation = operation
        super().__init__(f"Step {step} ({operation}): {message}")


class DataTransformer:
    """Applies a pipeline of transformations to data records.

    Each transformation is a dict with at minimum an 'op' key:

        {"op": "rename", "from": "old_name", "to": "new_name"}
        {"op": "cast", "field": "age", "type": "int"}
        {"op": "default", "field": "status", "value": "active"}
        {"op": "upper", "field": "name"}
        {"op": "lower", "field": "email"}
        {"op": "trim", "field": "name"}
        {"op": "replace", "field": "phone", "old": "-", "new": ""}
        {"op": "round", "field": "score", "decimals": 2}
        {"op": "clamp", "field": "age", "min": 0, "max": 150}
        {"op": "scale", "field": "price", "factor": 1.1}
        {"op": "date_format", "field": "dob", "input_format": "%Y-%m-%d", "output_format": "%d/%m/%Y"}
        {"op": "combine", "fields": ["first", "last"], "to": "full_name", "separator": " "}
        {"op": "split", "field": "full_name", "separator": " ", "to": ["first", "last"]}
        {"op": "conditional_set", "field": "tier", "condition_field": "score", "rules": [{"op": ">=", "value": 90, "set": "gold"}, {"op": ">=", "value": 50, "set": "silver"}], "default": "bronze"}
        {"op": "drop", "fields": ["temp", "internal_id"]}
        {"op": "copy", "from": "email", "to": "contact_email"}
        {"op": "coalesce", "fields": ["mobile", "home", "work"], "to": "phone"}
        {"op": "compute", "expression": "total = price * quantity"}
    """

    def __init__(self, pipeline: List[Dict[str, Any]]):
        self._pipeline = pipeline

    def transform(self, record: Dict[str, Any]) -> Dict[str, Any]:
        """Apply all transformations in order to a copy of the record.

        Args:
            record: Input data record

        Returns:
            Transformed copy of the record

        Raises:
            TransformError: If any transformation fails
        """
        result = dict(record)

        for i, step in enumerate(self._pipeline):
            op = step.get("op")

            if op == "rename":
                old_name = step["from"]
                new_name = step["to"]
                if old_name in result:
                    result[new_name] = result.pop(old_name)

            # All other operations are not yet implemented

        return result

    def transform_batch(self, records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        """Apply transformations to a batch of records.

        Returns list of transformed records. If a record fails,
        includes a dict with '_error' key instead.
        """
        results = []
        for record in records:
            try:
                results.append(self.transform(record))
            except TransformError as e:
                results.append({"_error": str(e), "_original": record})
        return results
